function Example({ value }) {
  useEffect(() => {
    // This runs after every render — initial mount and all re-renders
    console.log('rendered with value:', value);
    return () => {
      console.log('cleanup before next run, value was:', value);
    };
  }); // no second argument

  return <p>{value}</p>;
}

// Console on mount (value = 'a'):
// rendered with value: a
//
// Console on re-render (value = 'b'):
// cleanup before next run, value was: a
// rendered with value: b

useEffect(() => {
  const id = setInterval(() => console.log('tick'), 1000);
  return () => clearInterval(id); // cleanup before next render
}); // no array

// On every re-render:
//   clearInterval(previousId)  ← cleanup
//   setInterval(...)           ← new effect
//
// Result: the interval is re-registered on every render.
// Adding [] stops re-registration; adding [dep] makes it conditional.

// ✗ INFINITE LOOP — do not do this
function Broken() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    setCount(count + 1); // triggers re-render → effect fires again → ...
  }); // no dependency array

  return <p>{count}</p>; // browser freezes
}

// Fix: use a dependency array and derive the new value correctly
useEffect(() => {
  setCount(c => c + 1);
}, []); // runs once only

// Sync a third-party focus manager to the current focused element
function FocusTracker() {
  const ref = useRef(null);

  useEffect(() => {
    // focusManager reads the DOM; running after every render keeps it current
    focusManager.update(ref.current);
    // No state update — no re-render loop
  }); // correct: no array

  return <div ref={ref} tabIndex={0}>Focusable</div>;
}

function Canvas({ draw, width, height }) {
  const ref = useRef(null);

  useEffect(() => {
    const ctx = ref.current.getContext('2d');
    ctx.clearRect(0, 0, width, height);
    draw(ctx); // draw() writes to canvas — no setState call
  }); // runs after every render, canvas reflects latest props

  return <canvas ref={ref} width={width} height={height} />;
}

// Alternative with explicit deps (more efficient but must be maintained):
// useEffect(() => { ... }, [draw, width, height]);

function DebugLogger({ name, ...props }) {
  useEffect(() => {
    console.group(`[${name}] render`);
    Object.entries(props).forEach(([k, v]) => console.log(k, v));
    console.groupEnd();
  }); // intentionally no array — log on every render
}

// Runs after every render, AFTER paint (non-blocking)
useEffect(() => {
  externalLib.sync(containerRef.current);
});

// Runs after every render, BEFORE paint (blocking — use sparingly)
useLayoutEffect(() => {
  const height = containerRef.current.offsetHeight;
  setMeasured(height); // safe here — no flicker since it happens pre-paint
});

// Step 0: no array — always runs
useEffect(() => {
  document.title = `${user.name} — Dashboard`;
});

// Step 1: add dependency array — ESLint identifies required deps
useEffect(() => {
  document.title = `${user.name} — Dashboard`;
}, [user.name]); // now re-runs only when user.name changes

// Result: effect still runs on mount (first render),
// then only when user.name changes — not on every other re-render.

const renderCount = useRef(0);

useEffect(() => {
  renderCount.current += 1;
  console.log(`Effect ran ${renderCount.current} time(s)`);
}); // counts up on every render

// With [] — logs only once
// With [dep] — logs once per dep change
// With no array — logs every render

// Useful during development to diagnose unexpected re-renders
// caused by parent re-renders or unstable reference props.

function Counter({ step }) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    // Always sees the latest 'step' — no stale closure possible
    console.log(`count=${count}, step=${step}`);
  }); // no array
}

// If step prop changes from 1 to 5:
// Effect re-runs with step = 5 immediately after the re-render
// No stale value from a previous render is retained

// Class equivalent of a no-array useEffect:
class Example extends React.Component {
  componentDidMount() {
    this.logRender(); // on mount
  }
  componentDidUpdate() {
    this.logRender(); // on every update
  }
  logRender() {
    console.log('rendered:', this.props.value);
  }
}

// Equivalent hook form:
function Example({ value }) {
  useEffect(() => {
    console.log('rendered:', value);
  }); // single hook replaces both lifecycle methods
}

function Noisy() {
  useEffect(() => {
    console.log('effect');
    return () => console.log('cleanup');
  }); // no array
  return <p>Hello</p>;
}

