// startTransition defers renders; effects still fire only after commit
function SearchResults({ query }) {
  useEffect(() => {
    analytics.logSearch(query); // fires once per committed render
  }); // no array

  return <ResultList query={query} />;
}

// If query changes rapidly (user typing),
// React may abandon intermediate renders.
// analytics.logSearch fires only for renders that actually committed.

// Before: no array — fires on every render including unrelated ones
function UserBadge({ userId, theme }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetch(`/api/users/${userId}`).then(r => r.json()).then(setUser);
  }); // re-fetches whenever 'theme' changes too — wasteful!
}

// After: [userId] — only re-fetches when userId changes
function UserBadge({ userId, theme }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const ctrl = new AbortController();
    fetch(`/api/users/${userId}`, { signal: ctrl.signal })
      .then(r => r.json()).then(setUser);
    return () => ctrl.abort();
  }, [userId]); // only runs when userId changes
}

// Stage 1: no array — confirm the effect works
useEffect(() => {
  feedLibrary.setData(items, config);
});

// Stage 2: add suggested deps after ESLint check
useEffect(() => {
  feedLibrary.setData(items, config);
}, [items, config]); // now only re-runs when items or config change
